# Utility module for shape calculations
from shapes import Rectangle

# Calculate total area of shapes using a list
def total_area(widths: list[float], heights: list[float]) -> float:
    total: float = 0.0
    i: int = 0
    while i < len(widths):
        total = total + (widths[i] * heights[i])
        i = i + 1
    return total

# Create a square (special rectangle)
def create_square(side: float) -> Rectangle:
    return Rectangle(side, side)

# Scale rectangle dimensions
def scale_width(width: float, factor: float) -> float:
    return width * factor
